<template>


	<view class="wrap">
		<!-- 
		<u-navbar :custom-back="backpage">
			<u-search v-model="keyword" placeholder="请输入订单号或商品名称" height="56" @search="search" @custom="search">
			</u-search>

		</u-navbar> -->
		<view class="u-tabs-box">
			<u-tabs-swiper :active-color="'#f29100'" ref="tabs" :list="orderList" :current="current" @change="change"
				:is-scroll="false" swiperWidth="750"></u-tabs-swiper>
		</view>

		<scroll-view scroll-y style="height: 100%;width: 100%;" :style="status == 2 ?'height:calc(100% - 200rpx)':''"
			@scrolltolower="reachBottom">
			<view class="page-box">
				<view class="order" v-for="(order, orderindex) in  list" :key="order.id">
					<view class="top">
						<view class="left">

							<view class="store">提现方式：{{order.way_name}} </view>
							<!-- <u-icon name="zhuanfa" :size="30" color="rgb(94,94,94)"></u-icon> -->
							<!-- <u-icon name="arrow-right" color="rgb(203,203,203)" :size="26"></u-icon> -->
						</view>
						<view class="right" :style="{
									color:statusColor[order.status].color
								}">{{ orderList[order.status].name }}</view>
					</view>
					<view class="item">

						<view class="content">
							<view class="content-box">
								<view class="label">
									提现账号
								</view>
								<view class="value">
									{{order.account}}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									真实姓名
								</view>
								<view class="value">
									{{order.true_name}}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									提现金额
								</view>
								<view class="value">
									{{$util.bcadd(order.money,order.fee,2)}}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									费率
								</view>
								<view class="value">
									{{order.fee}}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									到账金额
								</view>
								<view class="value">
									{{order.money}}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									申请时间
								</view>
								<view class="value">
									{{order.create_time}}
								</view>
							</view>
							<view class="content-box" v-if="order.mark">
								<view class="label">
									备注
								</view>
								<view class="value">
									{{order.mark}}
								</view>
							</view>
						</view>

					</view>

					<view class="bottom">
						<!-- <view class="more">
										<u-icon name="more-dot-fill" color="rgb(203,203,203)"></u-icon>
									</view> -->
						<!-- <view class="logistics btn">详情</view> -->

						<!-- <view class="evaluate btn" v-if="order.status == 0">立即支付</view> -->
						<!-- <view class="exchange btn" @click="$util.on('/pages/buyer/addcomplain?ordersn='+order.ordersn)">编辑
						</view>
					<view class="exchange btn" style="color: red;" @click="$util.on('/pages/buyer/addcomplain?ordersn='+order.ordersn)">删除
						</view> -->
					</view>
				</view>



				<u-loadmore :status="loadStatus" icon-type="circle" v-if="list.length >0 && loaded" />
			</view>
			<u-empty v-if="loaded &&  list.length == 0"></u-empty>


		</scroll-view>
		<view class="" v-if="status ==2">
			<view class="" style="text-align: right;padding: 20rpx; ">
				已累计提现 :<text style="color: red;font-size: 40rpx;font-weight: 500;">{{total_money}}</text> 元
			</view>

		</view>
	</view>



</template>

<script>
	export default {
		data() {
			return {

				keyword: '',
				sys: this.$util.sys(),
				limit: 10,
				orderList: [{
						name: '全部',
						loadStatus: 'loadmore',
						page: 1,
						status: -1,
						count: 0,
						list: []
					},
					{
						name: '未处理',
						loadStatus: 'loadmore',
						page: 1,
						status: 1,
						count: 0,
						list: []
					},
					{
						name: '处理成功',
						loadStatus: 'loadmore',
						page: 1,
						status: 2,
						count: 0,
						list: []
					},
					{
						name: '处理失败',
						loadStatus: 'loadmore',
						page: 1,
						status: 3,
						count: 0,
						list: []
					},

				],


				statusColor: [{
						color: '#999'
					},
					{
						color: '#ccc'
					},
					{
						color: '#90dd90'
					},
					{
						color: '#f00'
					},
					{
						color: '#ccc'
					},
					{
						color: '#f00'
					}
				],


				loadStatus: 'loadmore',
				page: 1,
				status: -1,
				count: 0,
				list: [],
				current: 0,
				swiperCurrent: 0,
				loaded: false,

				total_money: 0,
				dx: 0,
			};
		},
		onLoad(e) {


			if (e.status) {
				this.swiperCurrent = e.status
				this.current = e.status

			}

			this.loadData(this.swiperCurrent);
		},
		computed: {
			// 价格小数
			priceDecimal() {
				return val => {
					if (val !== parseInt(val)) return val.split('.')[1];
					else return '00';
				};
			},
			// 价格整数
			priceInt() {
				return val => {
					if (val !== parseInt(val)) return val.split('.')[0];
					else return val;
				};
			}
		},
		methods: {
			backpage() {
				this.$util.back()
			},
			paste(val) {

				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			reachBottom() {


				setTimeout(() => {
					this.loadData(this.current);
				}, 200);

			},
			search() {
				this.orderList[0].list = []
				this.orderList[0].page = 1
				this.current = 0
				this.swiperCurrent = 0
				this.page = 1
				this.list = []
				this.loadData(0);


			},
			// 页面数据
			async loadData(idx) {

				uni.showLoading({
					mask: true,
					title: '加载中...',

				})
				await this.$u.api.drawlog({
						status: this.status,
						keyword: this.keyword,
						page: this.page,
						limit: this.limit,
					})
					.then(res => {

						this.total_money = res.total_money
						if (res.list.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res.list)

							} else {
								this.list = res.list

							}

							if (res.list.length < this.limit) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}


							this.page++
						}
					}).catch(res => {})

				this.loaded = true

				uni.hideLoading()

			},
			// 总价
			totalPrice(item) {
				let price = 0;
				item.map(val => {
					price += parseFloat(val.price);
				});
				return price.toFixed(2);
			},
			// 总件数
			totalNum(item) {
				let num = 0;
				item.map(val => {
					num += val.number;
				});
				return num;
			},
			// tab栏切换
			change(index) {
				this.swiperCurrent = index;
				this.current = index;
				this.list = []
				this.page = 1;
				this.status = this.orderList[index].status;
				this.loadData(index);
			},
			transition({
				detail: {
					dx
				}
			}) {

				this.$refs.tabs.setDx(dx);
			},
			animationfinish({
				detail: {
					current
				}
			}) {

				this.$refs.tabs.setFinishCurrent(current);
				this.swiperCurrent = current;
				this.current = current;
				if (!this.orderList[current].loaded) {
					this.loadData(current)
				}
			}
		}
	};
</script>



<style lang="scss" scoped scoped>
	page {
		height: 100%;
		background-color: #f2f2f2;
	}

	.order {
		width: 710rpx;
		background-color: #ffffff;
		margin: 20rpx auto;
		border-radius: 20rpx;
		box-sizing: border-box;
		padding: 20rpx;
		font-size: 28rpx;

		.top {
			display: flex;
			justify-content: space-between;

			.left {
				display: flex;
				align-items: center;

				.store {
					margin: 0 10rpx;
					font-size: 32rpx;
					font-weight: bold;
				}
			}

			.right {
				color: $u-type-warning-dark;
			}
		}

		.item {
			display: flex;
			margin: 20rpx 0 0;
			justify-content: space-between;

			.left {
				margin-right: 20rpx;

				image {
					width: 160rpx;
					height: 160rpx;
					border-radius: 10rpx;
				}
			}

			.content {
				width: 100%;

				.title {
					font-size: 28rpx;
					line-height: 50rpx;
				}

				.type {
					margin: 10rpx 0;
					font-size: 24rpx;
					color: $u-tips-color;
				}

				.delivery-time {
					// color: #e5d001;
					font-size: 24rpx;
				}
			}

			.right {
				margin-left: 10rpx;
				padding-top: 8rpx;
				text-align: right;

				.decimal {
					font-size: 24rpx;
					margin-top: 4rpx;
				}

				.number {
					color: $u-tips-color;
					font-size: 24rpx;
				}
			}

			.content-box {
				width: 100%;
				display: flex;
				gap: 20rpx;
				justify-content: space-between;
			}
		}

		.total {
			// margin-top: 20rpx;
			text-align: right;
			font-size: 24rpx;

			.total-price {
				font-size: 32rpx;
			}

			.decimal {
				font-size: 24rpx;
				margin-top: 4rpx;
			}
		}

		.bottom {
			display: flex;
			margin-top: 20rpx;
			padding: 0 10rpx;
			gap: 20rpx;
			justify-content: flex-end;
			align-items: center;

			.btn {
				line-height: 52rpx;
				width: 160rpx;
				border-radius: 26rpx;
				border: 2rpx solid $u-border-color;
				font-size: 26rpx;
				text-align: center;
				color: $u-type-info-dark;
			}

			.evaluate {
				color: $u-type-warning-dark;
				border-color: $u-type-warning-dark;
			}
		}
	}

	.centre {
		text-align: center;
		margin: 200rpx auto;
		font-size: 32rpx;

		image {
			width: 164rpx;
			height: 164rpx;
			border-radius: 50%;
			margin-bottom: 20rpx;
		}

		.tips {
			font-size: 24rpx;
			color: #999999;
			margin-top: 20rpx;
		}

		.btn {
			margin: 80rpx auto;
			width: 200rpx;
			border-radius: 32rpx;
			line-height: 64rpx;
			color: #ffffff;
			font-size: 26rpx;
			background: linear-gradient(270deg, rgba(249, 116, 90, 1) 0%, rgba(255, 158, 1, 1) 100%);
		}
	}

	.wrap {
		display: flex;
		flex-direction: column;
		height: calc(100vh - var(--window-top));
		width: 100%;
	}

	.swiper-box {
		flex: 1;
		background-color: #f4f5f8;
	}

	.swiper-item {
		height: 100%;
	}
</style>